parameters.jsCode:
const body = $json.body || $json;

const player = body.player_name || body.player || body.username || 'Unknown';
const steamId = body.steam_id || body.steamid || '';
const reason = body.reason || body.ban_reason || 'Anti-Cheat Detection';
const server = body.server_name || body.server || 'Unknown Server';
const source = body.source || body.plugin || 'Unknown';
const duration = body.duration || body.ban_duration || 'Permanent';
const ip = body.ip || '';

// Severity color based on source
let color = 16711680; // red
if (source.includes('VAC')) color = 10038562; // dark red
else if (source.includes('SMAC')) color = 16744448; // orange
else if (source.includes('UAC')) color = 15105570; // amber

return [{ json: {
  player, steamId, reason, server, source, duration, ip,
  color,
  steamUrl: steamId ? `https://steamcommunity.com/profiles/${steamId}` : '',
  timestamp: new Date().toISOString()
}}];

